/**
 * TaskInput コンポーネント
 * US-001対応: タスク作成エリア
 * DA仕様のshakeアニメーション・エラーフィードバック・フォーカス管理を実装
 */

import React, { useState, useRef, useCallback } from 'react';
import { useTodos } from '../hooks/useTodos';

export function TaskInput(): React.JSX.Element {
  const { addTodo } = useTodos();
  const [value, setValue] = useState('');
  const [isShaking, setIsShaking] = useState(false);
  const [showHelper, setShowHelper] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const helperTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const triggerShake = useCallback(() => {
    setIsShaking(true);
    setShowHelper(true);

    // shakeアニメーション終了後にクラスを外す（400ms）
    setTimeout(() => setIsShaking(false), 400);

    // ヘルパーテキストは2000ms後に非表示（DA仕様）
    if (helperTimerRef.current) clearTimeout(helperTimerRef.current);
    helperTimerRef.current = setTimeout(() => setShowHelper(false), 2000);
  }, []);

  const handleSubmit = useCallback(() => {
    const trimmed = value.trim();
    if (trimmed.length === 0) {
      // AC-001-2: 空入力の場合はかわいいフィードバック
      triggerShake();
      inputRef.current?.focus();
      return;
    }
    // AC-001-1: タスク追加成功
    addTodo(trimmed);
    setValue('');
    // 連続追加サポートのためフォーカスを維持
    inputRef.current?.focus();
  }, [value, addTodo, triggerShake]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter') {
        handleSubmit();
      }
    },
    [handleSubmit],
  );

  return (
    <div className="task-input">
      <div className={`task-input__container${isShaking ? ' task-input__container--shake' : ''}`}>
        <input
          ref={inputRef}
          className="task-input__field"
          type="text"
          value={value}
          onChange={(e) => setValue(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="新しいタスクを入力..."
          maxLength={100}
          aria-label="新しいタスク名"
          autoComplete="off"
        />
        <button
          className="task-input__add-btn"
          onClick={handleSubmit}
          aria-label="タスクを追加する"
          type="button"
        >
          ＋ 追加
        </button>
      </div>
      {showHelper && (
        <p className="task-input__helper" role="alert" aria-live="polite">
          タスク名を入力してね 💕
        </p>
      )}
    </div>
  );
}
</file>

<file path="src/components/CompletionCelebration.tsx">
/**
 * CompletionCelebration コンポーネント
 * DA仕様: CSS keyframes + クリップパスのみ（ライブラリ不使用）
 * チェックボタン周辺にconfettiパーティクルを表示する
 */

import React, { useEffect, useRef } from 'react';

interface CompletionCelebrationProps {
  active: boolean;
  onComplete: () => void;
}

const CONFETTI_COLORS = ['#FF6B9D', '#D8A5E8', '#A8E6CF', '#FFD700'];
const PARTICLE_COUNT = 6;

export function CompletionCelebration({
  active,
  onComplete,
}: CompletionCelebrationProps): React.JSX.Element | null {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!active || !containerRef.current) return;

    const container = containerRef.current;
    const particles: HTMLSpanElement[] = [];

    // パーティクルを動的に生成（DA仕様: count=6, spread=60px）
    for (let i = 0; i < PARTICLE_COUNT; i++) {
      const particle = document.createElement('span');
      const angle = (360 / PARTICLE_COUNT) * i;
      const color = CONFETTI_COLORS[i % CONFETTI_COLORS.length];
      const size = 4 + Math.random() * 4; // 4〜8px（DA仕様）

      particle.className = 'confetti-particle';
      particle.style.setProperty('--angle', `${angle}deg`);
      particle.style.setProperty('--color', color);
      particle.style.setProperty('--size', `${size}px`);
      container.appendChild(particle);
      particles.push(particle);
    }

    // 600ms後にパーティクルをクリーンアップ（DA仕様: duration 600ms）
    const cleanupTimer = setTimeout(() => {
      particles.forEach((p) => {
        if (container.contains(p)) container.removeChild(p);
      });
      onComplete();
    }, 700);

    return () => {
      clearTimeout(cleanupTimer);
      particles.forEach((p) => {
        if (container.contains(p)) container.removeChild(p);
      });
    };
  }, [active, onComplete]);

  if (!active) return null;

  return (
    <div className="confetti-container" ref={containerRef} aria-hidden="true">
      <span className="confetti-message">やったね！ 🎉</span>
    </div>
  );
}
</file>

<file path="src/components/TaskItem.tsx">
/**
 * TaskItem コンポーネント
 * US-001〜003対応: 個別タスクカード
 * DA仕様: default/completed/hover/deletingの4ステート
 * touch-action: pan-y をスクロール競合防止のため適用（モバイルタッチハンドオフ仕様）
 */

import React, { useState, useCallback, useRef, useEffect } from 'react';
import type { Todo } from '../types/todo';
import { useTodos } from '../hooks/useTodos';
import { useUiState } from '../hooks/useUiState';
import { CompletionCelebration } from './CompletionCelebration';

interface TaskItemProps {
  todo: Todo;
  isNew?: boolean;
}

export function TaskItem({ todo, isNew = false }: TaskItemProps): React.JSX.Element {
  const { toggleTodo, deleteTodo } = useTodos();
  const { showDeleteNotification } = useUiState();
  const [isDeleting, setIsDeleting] = useState(false);
  const [isEntering, setIsEntering] = useState(isNew);
  const [showCelebration, setShowCelebration] = useState(false);
  const prevCompletedRef = useRef(todo.completed);

  // 新規アイテムのenteringアニメーション（DA仕様: slideDown + fadeIn 300ms）
  useEffect(() => {
    if (isEntering) {
      const t = setTimeout(() => setIsEntering(false), 300);
      return () => clearTimeout(t);
    }
  }, [isEntering]);

  // 完了状態変化時にconfettiをトリガー
  useEffect(() => {
    if (todo.completed && !prevCompletedRef.current) {
      setShowCelebration(true);
    }
    prevCompletedRef.current = todo.completed;
  }, [todo.completed]);

  const handleToggle = useCallback(() => {
    toggleTodo(todo.id);
  }, [toggleTodo, todo.id]);

  const handleDelete = useCallback(() => {
    setIsDeleting(true);
    // DA仕様: deleteアニメーション280ms後にContextから削除
    setTimeout(() => {
      const result = deleteTodo(todo.id);
      if (result) {
        showDeleteNotification({
          type: 'DELETE',
          todo: result.todo,
          originalIndex: result.originalIndex,
        });
      }
    }, 280);
  }, [deleteTodo, showDeleteNotification, todo.id]);

  const handleCelebrationComplete = useCallback(() => {
    setShowCelebration(false);
  }, []);

  const containerClass = [
    'task-item',
    todo.completed ? 'task-item--completed' : '',
    isDeleting ? 'task-item--deleting' : '',
    isEntering ? 'task-item--entering' : '',
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <li className={containerClass} role="listitem">
      <div className="task-item__check-wrapper">
        <button
          className={`task-item__check-toggle${todo.completed ? ' task-item__check-toggle--checked' : ''}`}
          onClick={handleToggle}
          aria-label="タスクを完了にする"
          aria-pressed={todo.completed}
          type="button"
        >
          {todo.completed && <span className="task-item__check-icon" aria-hidden="true">✓</span>}
        </button>
        <CompletionCelebration active={showCelebration} onComplete={handleCelebrationComplete} />
      </div>

      <span className={`task-item__title${todo.completed ? ' task-item__title--completed' : ''}`}>
        {todo.title}
      </span>

      <button
        className="task-item__delete-btn"
        onClick={handleDelete}
        aria-label="タスクを削除する"
        type="button"
        disabled={isDeleting}
      >
        <svg
          width="20"
          height="20"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          strokeWidth="2"
          strokeLinecap="round"
          strokeLinejoin="round"
          aria-hidden="true"
        >
          <polyline points="3 6 5 6 21 6" />
          <path d="M19 6l-1 14a2 2 0 01-2 2H8a2 2 0 01-2-2L5 6" />
          <path d="M10 11v6M14 11v6" />
          <path d="M9 6V4a1 1 0 011-1h4a1 1 0 011 1v2" />
        </svg>
      </button>
    </li>
  );
}
